void add_tok(char*s,int n,int id){cp(tb[id],s);tl[id]=n;}
void enc_bpe(char*s,int n,int*ids,int*cnt){
 char p[N][80];int pl[N];
 int c=0;
 for(int i=0;i<n;i++){int l=bl[(unchar)s[i]];cp(p[c],(char*)be[(unchar)s[i]]);pl[c++]=l;}
