   b=rank(mp,len);
   if(b>=0){bi=i;break;}
  }
  if(bi<0)break;
  memcpy(p[bi]+pl[bi],p[bi+1],pl[bi+1]);
  pl[bi]+=pl[bi+1];
  for(int i=bi+1;i<c-1;i++){memcpy(p[i],p[i+1],80);pl[i]=pl[i+1];}
  c--;
 }
 *cnt=c;
 for(int i=0;i<c;i++)ids[i]=get_tok(p[i],pl[i]);
